# Basic conditional with elif chain
def classify_token_count(n: int) -> str:
    if n <= 0:
        return "empty"
    elif n < 512:
        return "short"
    elif n < 4096:
        return "medium"
    elif n < 32768:
        return "long"
    else:
        return "very_long"

