import time

MAX_TURNS = 10
BUDGET_TOKENS = 8000

def run_agent(messages: list, tools: dict) -> str:
    turns = 0
    tokens_used = 0

    while turns < MAX_TURNS and tokens_used < BUDGET_TOKENS:
        response = call_llm(messages)
        tokens_used += response.usage.total_tokens
        turns += 1

        if response.finish_reason == "stop":
            return response.content   # natural completion

        if response.finish_reason == "tool_calls":
            for tc in response.tool_calls:
                result = tools[tc.name](**tc.arguments)
                messages.append({"role": "tool", "content": str(result)})
        else:
            # unexpected finish reason
            break

    return f"Terminated after {turns} turns / {tokens_used} tokens"


# Polling loop — wait for async job
def wait_for_job(job_id: str, timeout: float = 60.0) -> dict:
    deadline = time.monotonic() + timeout
    while time.monotonic() < deadline:
        status = get_job_status(job_id)
        if status["state"] in ("complete", "failed"):
            return status
        time.sleep(2)
    raise TimeoutError(f"Job {job_id} did not complete within {timeout}s")

# break + continue example
def select_context_docs(candidates: list, limit: int = 5) -> list:
    selected = []
    for doc in candidates:
        if doc["score"] < 0.5:
            continue           # skip poor matches
        if doc["flagged"]:
            continue           # skip unsafe content
        selected.append(doc)
        if len(selected) >= limit:
            break              # stop once we have enough
    return selected


# for/else — search pattern
def find_tool(name: str, tools: list) -> dict | None:
    for tool in tools:
        if tool["name"] == name:
            return tool
    else:
        # runs only if break was never hit (i.e., not found)
        return None


# while/else — retry with explicit not-found
def fetch_with_retry(url: str, max_retries: int = 3) -> bytes:
    attempt = 0
    while attempt < max_retries:
        try:
            return http_get(url)
        except TransientError:
            attempt += 1
            time.sleep(2 ** attempt)
    else:
        raise RuntimeError(f"All {max_retries} retries failed for {url}")

