# Guard clause style (easy to read)
def process_result(result):
    if result is None:
        return None
    if not result.ok:
        raise ValueError(result.error)
    if not result.data:
        return []
    return transform(result.data)

import time, random

def with_backoff(fn, *, retries: int = 5, base: float = 0.5, jitter: bool = True):
    """Call fn(), retrying on TransientError with exponential backoff."""
    last_exc = None
    for attempt in range(retries):
        try:
            return fn()
        except TransientError as exc:
            last_exc = exc
            delay = base * (2 ** attempt)
            if jitter:
                delay *= random.uniform(0.8, 1.2)
            time.sleep(delay)
    raise RuntimeError(f"All {retries} attempts failed") from last_exc


