# CORRECT — explicit turn cap
def safe_agent(messages, max_turns=20):
    for _ in range(max_turns):
        resp = llm(messages)
        if resp.finish_reason == "stop":
            return resp.content
        messages.append({"role": "assistant", "content": resp.content})
    raise RuntimeError("Max turns exceeded")
